            defaultValue: '0'
        },
        {
            key: 'info',
            label: '完整简介',
            defaultValue: 'on'
        }
    ];

    var valueMap = {
        // 访问模式
        '本地': '💻 本地',
        '云端': '☁️ 云端',

        // 开关状态
        'on': '✅ 开启',
