            java.androidId(); 
            return true; 
        } catch (e) {
            return false; 
        }
    }
}

function isQRead() {
    let { java } = this;
    try {
        return java.qread && java.qread() == 1;
    } catch (e) {
        return false;
    }
}

function getServerHost() {
	let { source } = this;
    try {
        const config = JSON.parse(source.getVariable());
        return config?.[0]?.host || source.bookSourceUrl;
    } catch(e) {
        return source.bookSourceUrl;
    }
}

function getSessionId() {
    const { cookie, source } = this;
    try {
        let cookieHeader = String(cookie.getCookie('fanqienovel.com'));
        let sessionId = cookieHeader.match(/sessionid=([^;]+)/)?.[1] || null;

        if (sessionId) {
            return sessionId;
        }
    } catch (e) {
    }

    try {
        let loginInfo = source.getLoginInfoMap() || {};
        return loginInfo['番茄登录Token'] || "";
    } catch (e) {
        return "";
    }
}

function splitArray(input, size) {
  let output = []
  for (let i = 0; i < input.length; i += size) {
    output.push(input.slice(i, i + size))
  }
  return output
}

function getCommentIconColor() {
    let { source } = this;
    let color = "red";
    let loginInfo = source.getLoginInfoMap();
    if (loginInfo && loginInfo['段评图标颜色'] && loginInfo['段评图标颜色'].startsWith('#')) {
        color = loginInfo['段评图标颜色'];
    }
    return color;
}

function wrapContentForIOS(content) {
    if (deviceType.call(this)) {
        return content;
    }

    let lines = content.split('\n').map(line => {
        if (line.trim()) {
            return `<span rs-native>${line}</span>`;
        }
        return line;
    });

    return lines.join('\n');
}

function buildCommentUrl(sourceType, bid, cid, para) {
    let host = getServerHost.call(this);
    let aidParam = (!deviceType.call(this) || isQRead.call(this)) ? "&aid=web" : "";

    switch (sourceType) {
        case 'qm':
            return host + '/qm_comment?item_id=' + cid + '&book_id=' + bid + '&paragraph_id=' + para + aidParam;
        case 'fq':
        default:
            return host + '/idea_comment?item_id=' + cid + '&book_id=' + bid + '&para=' + para + '&sessionid=' + getSessionId.call(this) + aidParam;
    }
}

function getCommentSourceName(sourceType) {
    switch (sourceType) {
        case 'qm': return '七猫';
        case 'fq':
        default: return '番茄';
    }
}

function startCommentBrowser(url, title) {
    if (isQRead.call(this)) {
        this.java.startBrowserDp(url, title);
    } else {
        this.java.startBrowser(url, title);
    }
}

function createCommentHtmlTag(displayText, url, sourceName) {
    const encodedUrl = url.replace(/&/g, '&amp;');
    return '<comment count="' + displayText + '" onPress="java.' + 
           (isQRead.call(this) ? 'startBrowserDp' : 'startBrowser') + 
           '(\'' + encodedUrl + '\',\'' + sourceName + '段评\')" />';
}

function createSvg(number, color, bid, cid, para, sourceType = 'fq') {
    var displayText = number > 99 ? "99+" : number;
    var date = String(Date.now()).match(/(\d{6}$)/)[1];
    var loginInfoMap = {};
    if (this.source && typeof this.source.getLoginInfoMap == 'function') {
        loginInfoMap = this.source.getLoginInfoMap() || {};
    }
    var bubbleStyle = String(loginInfoMap['段评气泡样式'] || '0');

    let isIOS = !deviceType.call(this);
    if (isIOS) {
        let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
        let sourceName = getCommentSourceName(sourceType);
        return createCommentHtmlTag.call(this, displayText, commentUrl, sourceName);
    }

    var svg;
    if (bubbleStyle == '1') {
        svg = '<svg width="1000" height="833" xmlns="http://www.w3.org/2000/svg">' +
              '<rect x="30" y="20" width="940" height="793" rx="180" ry="180" fill="none" stroke="' + color + '" stroke-width="40" stroke-linejoin="round"/>' +
              '<text x="500" y="444" text-anchor="middle" font-size="333" fill="' + color + '" dy="0.3em" font-weight="700" opacity="0.9">' + displayText + '</text>' +
              '</svg>';
    } else if (bubbleStyle == '2') {
        svg = '<svg width="1000" height="1000" xmlns="http://www.w3.org/2000/svg">' +
              '<circle cx="500" cy="500" r="460" fill="none" stroke="' + color + '" stroke-width="40" stroke-linejoin="round"/>' +
              '<text x="500" y="500" font-family="Arial, sans-serif" text-anchor="middle" font-size="360" fill="' + color + '" dy="0.3em" font-weight="700" opacity="0.9">' + displayText + '</text>' +
              '</svg>';
    } else if (bubbleStyle == '3') {
        svg = '<svg width="160" height="120" xmlns="http://www.w3.org/2000/svg"><path d="M 55 10 L 120 10 Q 150 10 150 40 L 150 80 Q 150 110 120 110 L 55 110 Q 25 110 25 80 L 25 75 L 3 60 L 25 45 L 25 40 Q 25 10 55 10 Z" fill="none" stroke="' + color + '" stroke-width="2" stroke-linejoin="round"/><text x="87" y="75" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="50" font-weight="bold" fill="' + color + '">' + displayText + '</text></svg>';
    } else {
        svg = '<svg width="1000" height="909" xmlns="http://www.w3.org/2000/svg">' +
              '<path d="M80,80 h840 a60,60 0 0 1 60,60 v580 a60,60 0 0 1 -60,60 h-620 l-140,90 v-90 h-80 a60,60 0 0 1 -60,-60 v-580 a60,60 0 0 1 60,-60 z" ' +
              'fill="none" stroke="' + color + '" stroke-width="16" stroke-linejoin="round"/>' +
              '<text x="500" y="450" text-anchor="middle" ' + 'font-size="360" fill="' + color + '" dy="0.3em">' + displayText + '</text>' +
              '</svg>';
    }

    var encodedSvg = this.java.base64Encode(svg);

    let jsFunction;
    switch (sourceType) {
        case 'qm':
            jsFunction = 'showQmCmt';
            break;
        case 'fq':
        default:
            jsFunction = 'showCmt';
            break;
    }

    return 'data:image/svg+xml;base64,' + encodedSvg + ',{\'js\':\'' + jsFunction + '("' + bid + '","' + cid + '","' + para + '","' + date + '")\',\'style\':\'TEXT\'}';
}

function checkClickRateLimit(lastCallKey) {
    let { cache } = this;
    let lastCallTime = cache.getFromMemory(lastCallKey) || 0;
    let currentTime = Date.now();

    if (currentTime - lastCallTime < 1000) {
        return false;
    }
    cache.putMemory(lastCallKey, currentTime);
    return true;
}

function handleCommentClick(sourceType, bid, cid, para, date, cacheKey) {
    let { cache } = this;
    let mname = cacheKey;
    let load = (cache.getFromMemory(mname) ?? "-").split("-");

    if (load[0] != "1" || load[1] != date) {
        cache.putMemory(mname, "1-" + date);
        return;
    }

    let lastCallKey = `last_call_${sourceType}_${bid}_${cid}_${para}`;
    if (!checkClickRateLimit.call(this, lastCallKey)) {
        return;
    }

    let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
    let title = cache.getFromMemory(mname + "-text") ?? getCommentSourceName(sourceType) + "段评";

    startCommentBrowser.call(this, commentUrl, title);
}

function getComments(content, bid, cid, sourceType = 'fq', contentMd5 = null) {
    let { java, cache, source } = this;
    let host = getServerHost.call(this);
    try {
        let lines = content
            .replace(/(<img[^>]*?>)\n/g, "$1")
            .split("\n")
            .filter(line => line.trim());

        if (sourceType == 'qm') {
            if (!contentMd5) return wrapContentForIOS.call(this, content);

            let apiUrl = `${host}/proxy_qmidea?action=paragraph_bubbles&book_id=${bid}&item_id=${cid}&content_md5=${contentMd5}`;
            let response = java.ajax(apiUrl);
            let data = JSON.parse(response).data;

            if (data && data.chapters && data.chapters.length > 0) {
                let chapterData = data.chapters[0];
                if (chapterData.bubbles) {
                    chapterData.bubbles.forEach((bubble, bubbleIndex) => {
                        let paraMd5 = bubble.p;
                        let count = parseInt(bubble.c) || 0;

                        if (count > 0 && bubbleIndex < lines.length) {
                            let paraIndex = bubbleIndex;

                            cache.putMemory(`qm-${bid}-${cid}-${paraMd5}-text`, lines[paraIndex]);

                            let color = getCommentIconColor.call(this);
                            let commentTag = createSvg.call(this, count, color, bid, cid, paraMd5, sourceType);
                            if (deviceType.call(this)) {
                                lines[paraIndex] += `<img src="${commentTag}">`;
                            } else {
                                lines[paraIndex] += commentTag;
                            }
                        }
                    });
                }
            }
        } else {
            let apiUrl = `${host}/proxy_idea?item_id=${cid}`;
            let comments = java.ajax(apiUrl);
            let raw = JSON.parse(comments).data.data;

            Object.keys(raw).forEach((x) => {
                cache.putMemory(`fq-${bid}-${cid}-${x}-text`, lines[x]);

                let color = getCommentIconColor.call(this);
                let commentTag = createSvg.call(this, raw[x].count, color, bid, cid, x, sourceType);
                if (deviceType.call(this)) {
                    lines[x] += `<img src="${commentTag}">`;
                } else {
                    lines[x] += commentTag;
                }
            });
        }

        let result = lines.join("\n");
        return wrapContentForIOS.call(this, result);
    } catch (e) {
        return wrapContentForIOS.call(this, content);
    }
}

function showCmt(bid, cid, para, date) {
    handleCommentClick.call(this, 'fq', bid, cid, para, date, `fq-${bid}-${cid}-${para}`);
}

function showQmCmt(bid, cid, para, date) {
    handleCommentClick.call(this, 'qm', bid, cid, para, date, `qm-${bid}-${cid}-${para}`);
}

function getSecretKey() {
	let { java, source } = this;
    const loginInfo = source.getLoginInfoMap();
    const key = loginInfo['密钥'] || '';
    if (!key) {
        java.toast("请先填写密钥");
    }
    return java.base64Encode(key);
}

function getBookIdFromUrl(baseUrl) {
	let { java, source } = this;
    let finalUrl;
    let urlMatch = baseUrl.match(/url=([^&]*)/);

    if (urlMatch && urlMatch[1]) {
        finalUrl = java.base64Decode(urlMatch[1]);
    } else {
        let fqurl = JSON.parse(java.base64Decode(baseUrl.split(",")[1]));
        finalUrl = java.base64Decode(fqurl.url);
    }

    let bookIdMatch = finalUrl.match(/book_id=(\d{19})/);
    return bookIdMatch ? bookIdMatch[1] : null;
}

function getBookData(bookId) {
	let { java, source } = this;
    let newUrl = "https://api5-normal-sinfonlineb.fqnovel.com/reading/bookapi/multi-detail/v/?aid=1967&iid=1&version_code=999&book_id=" + bookId;
    let response = java.ajax(newUrl);
    let responseData = JSON.parse(response);

    if (Array.isArray(responseData.data)) {
        return responseData.data[0];
    } else {
        return responseData.data;
    }
}

function parseAuthors(authorsData) {
	let { java, source } = this;
    let authors = [];
    try {
        authors = authorsData ? JSON.parse(authorsData) : [];
    } catch(e) {
        authors = authorsData ? authorsData.replace(/[\[\]"]/g,'').split(',') : [];
    }
    return authors.length > 0 ? (authors[0].AuthorName || authors[0] || "") : "";
}

function getToneInfo(bookId) {
    if (!bookId) return "";

    try {
        let tones = "\n===================\n🎧AI音色编号信息: ";
        let info = JSON.parse(java.ajax(`https://reading.snssdk.com/reading/bookapi/audio/toneinfo/?book_id=${bookId}&aid=1967`));
        for (let i of (info.data.tts_tones ? info.data.tts_tones : [])) {
            tones += `\n${i.id} - ${i.title}${i.description ? "(" + i.description + ")" : ""}`;
        }
        return tones;
    } catch (e) {
        return "";
    }
}

function syncReadingHistory(bookId) {
    let { java, source } = this;
    if (bookId) {
        var sessionid = getSessionId.call(this);
        if (sessionid && sessionid.trim() !== "") {
            var syncUrl = getServerHost.call(this) + "/update_history?book_id=" + bookId + "&sessionid=" + sessionid;
            java.ajax(syncUrl);
        }
    }
}

function getSortKey() {
    let { java, source } = this;
    const loginInfo = source.getLoginInfoMap();
    const sortKey = loginInfo['番茄排序'] || '';
    if (!sortKey) {
        java.toast("请先填写番茄排序，参数请看源注释");
    }
    return sortKey;
}

