                maskedKey = keyValue.substring(0, 3) + "****" + keyValue.substring(keyValue.length - 4);
            } else {
                maskedKey = "****" + keyValue.substring(keyValue.length - 4);
            }

            var email = userInfo.email || "未绑定";
            var maskedEmail = "未绑定";
