// 当前书源版本号，切勿修改，否则影响更新的识别
const localVersion = '4.12.24';

function login(flag) {
    if (flag == undefined) {
        result = JSON.parse(source.getLoginInfo())
    } else {
        java.longToast("\n\n💞正在登录中...")
        putLoginInfo(JSON.stringify(result))
    }
    let base_url = getArgument('server')
    let zdyserver = String(result['自定义服务器(可不填)']);
    if (zdyserver.includes('http')) {
        setArgument('server', zdyserver);
        if (getKey(String(cookie.getCookie(base_url)))) {
            let cookies = cookie.getCookie(base_url)
try{cookie.removeCookie(base_url)} catch(e){}
            cookie.setCookie(zdyserver, cookies)
        }
        java.toast(`\n\n当前服务器为自定义服务器\n${zdyserver}\n\n切换服务器请先清空服务器地址中的数据`);
    }
    let zdytone_id = String(result['听书Ai音色填写后点击右上角✔'] || '');
    if (zdytone_id) {
        setArgument('tone_id', zdytone_id);
    } else {
        setArgument('tone_id', '默认音色');
    }
    let plcolor = String(result['自定义评论颜色(可不填)'] || '#000000');
    if (plcolor) {
        setArgument('plcolor', plcolor);
    } else {
        setArgument('plcolor', '#000000');
    }
    let zdysources = String(result['自定义搜索源(多个用英文,分割)'] || '');
    if (zdysources) {
        setArgument('source', zdysources);
    };
    base_url = getArgument('server')
    let register_email = String(result['邮箱'])
    let password = String(result['密码'])
    let key = String(result['密钥'] || '')

    //java.log(cookie.getCookie(base_url))
    if ((register_email && password || key) && !String(getKey(String(cookie.getCookie(base_url))))) {
        try{cookie.removeCookie(base_url)} catch(e){}
        let deviceKey = '';
        try {
            deviceKey = java.deviceID();
        } catch (e) {
            deviceKey = java.androidId();
        };
        let deviceId = deviceKey;
        if (register_email && password) {
            let options = JSON.stringify({
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    register_email: result['邮箱'],
                    password: result['密码']
                })
            })
            try {
                let data = JSON.parse(java.ajax(`${base_url}/login_api,${options}`))
                if (data.code == 0) {
                    //java.toast(deviceId)
                    java.toast("\n\n✅️登录成功")
                    cookie.setCookie(base_url, `qttoken=${data.key};deviceId=${deviceId}`)
                    result['密钥'] = data.key
                    putLoginInfo(JSON.stringify(result))
                } else {
                    java.toast('\n\n💔' + data.msg || "登录失败，请重试！")
                }
            } catch (e) {
                java.toast("\n\n💔登录失败，请重试！\n" + e.message)
            }
        } else {
            cookie.setCookie(base_url, `qttoken=${key};deviceId=${deviceId}`)
            let res = java.ajax(`${base_url}/user_api,{"method":"POST","headers":{"cookie":"${cookie.getCookie(base_url)}"}}`)
            try {
                res = JSON.parse(res)
                if (res.id != undefined) {
                    java.toast('\n\n密钥登录成功')
                    result['邮箱'] = res.email
                    putLoginInfo(JSON.stringify(result))
                } else {
                    throw new Error()
                }
            } catch (e) {
                java.log(e)
                java.toast("\n\n💔登录失败")
            }
        }
    } else if (flag && String(getKey(String(cookie.getCookie(base_url))))) {
        java.toast("\n\n当前✅️已登录，请🚫退出登录后重新登录");
        //checkStatus();
    } else if (flag) {
        java.toast("\n\n⛔️请先填写邮箱和密码");
    }
}

// 检测服务器
function checkNet() {
    let url = getArgument('server');
    java.longToast(`\n\n♻️正在检测：${url}\n请稍等~`);
    let date1 = new Date().getTime();
    let html = java.ajax(url + '/login');
    let date2 = new Date().getTime();
    let t = date2 - date1;
    let c = String(html).indexOf('大灰狼');
    let code = 1;
    let time = t / 1000 + 's';
    let logTime = '【' + url + '】\n┋┋\n' + '解析时间：' + time;
    if (c == -1 || t > 5000) {
        java.longToast('\n💔【访问失败提示】\n' + '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + logTime + '\n┋┋\n♣️当前接口无法访问(可能被墙)♣️\n┋┋\n请切换其他接口/切换网络环境\n┋┋' + '\n┗┅━┅━┅━┅━┅┅━┅━┅┛');
    } else if (t < 1000) {
        java.longToast('\n💖【网络环境优良】\n' + '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + logTime + '\n┋┋\n❤️延迟低，推荐使用此接口❤️\n┋┋\n网络环境优良，请继续保持状态\n┋┋' + '\n┗┅━┅━┅━┅━┅┅━┅━┅┛');
    } else if (t >= 1000 && t < 2000) {
        java.longToast('\n💛【网络环境一般】\n' + '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + logTime + '\n┋┋\n♦️延迟一般，勉强可使用♦️\n┋┋\n请切换其他接口或切换网络环境\n┋┋' + '\n┗┅━┅━┅━┅━┅┅━┅━┅┛');
    } else if (t >= 2000 && t < 5000) {
        java.longToast('\n💔【网络环境堪忧】\n' + '┏┅━┅━┅━┅━┅┅━┅━┅┓\n┋┋\n' + logTime + '\n┋┋\n♠延迟过高，不建议使用♠\n┋┋\n请切换其他接口或切换网络环境\n┋┋' + '\n┗┅━┅━┅━┅━┅┅━┅━┅┛');
    }
}

function isVips(res) {
    let isVIP = '';
    let vipEndTime = res.vip_end_time;
    let formattedDate = '';

    if (vipEndTime && vipEndTime !== 0) {
        let date = new Date(vipEndTime * 1000);
        formattedDate = `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
        let currentTime = Math.floor(Date.now() / 1000);
        let remainingDays = Math.ceil((vipEndTime - currentTime) / (24 * 60 * 60));
        if (currentTime > vipEndTime) {
            isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} (已过期)`;
        } else if (remainingDays <= 7) {
            isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} 剩余${remainingDays}天`;
        } else {
            if (vipEndTime < 1912946812) {
                isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"}(${formattedDate})`;
            } else {
                isVIP = `${res.vip_level === 1 ? "VIP" : "SVIP"} (永久)`;
            }
        }
    } else {
        isVIP = '您尚未开通VIP';
    }
    return isVIP;
}

